    function fmtRate(kb) {
      if (kb === null || kb === undefined || Number.isNaN(Number(kb))) return "—";
      const val = Number(kb);
      if (val >= 1024) return (val / 1024).toFixed(1) + " MB/s";
      return val.toFixed(1) + " KB/s";
    }

    function fmtLimit(raw) {
      if (raw === null || raw === undefined || raw === "" || raw === "0") return "Unlimited";
      const n = Number(raw);
      if (Number.isNaN(n)) return raw;
      return fmtRate(n);
