    function badgeClass(entry, state, stale) {
      if (stale) return "idle";
      if (entry.paused) return "paused";
      if (state === "synchronized") return "ok";
      if (state === "uploading" || state === "downloading") return "busy";
      if (state === "error") return "error";
      return "idle";
    }

    function badgeLabel(entry, state, stale) {
      if (stale) return "Offline";
      if (!entry.daemon_alive) return "Daemon stopped";
      if (entry.paused) return "Paused";
      if (state === "synchronized") return "Synchronized";
      if (state === "uploading") {
