        const rate = entry.repos[0]?.rate_kb;
        let label = "Uploading";
        if (pct !== null && pct !== undefined) label += " " + pct + "%";
        if (rate !== null && rate !== undefined && rate > 0) label += " · " + fmtRate(rate);
        return label;
      }
      if (state === "downloading") return "Downloading";
      if (state === "error") return "Error: " + (entry.repos[0]?.error || "unknown");
      if (state === "waiting") return "Waiting to sync";
      if (!state) return "Starting up…";
      return state;
